//! Server configuration.
//!
//! Layered with figment: built-in defaults ← TOML file ← `CHAOS_*` env vars.
//! The TOML file is `$CHAOS_CONFIG`, or `./chaos.toml` if present. On NixOS
//! the file will be generated by the future `services.chaos` module from
//! `config.modules.server.servicesList` (see docs/ARCHITECTURE.md).

use std::net::SocketAddr;
use std::path::PathBuf;

use chaos_domain::{BookmarkGroup, ColumnSize, ServiceDef, Widget};
use figment::Figment;
use figment::providers::{Env, Format, Serialized, Toml};
use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct Config {
    /// Address the HTTP server binds to.
    pub listen: SocketAddr,
    /// Directory with the built web frontend (trunk dist). When set, the
    /// server serves it with an SPA fallback to index.html.
    pub static_dir: Option<PathBuf>,
    /// SQLite database file (created on first start).
    pub db_path: PathBuf,
    /// On-disk cache for proxied service/bookmark icons.
    pub icon_cache_dir: PathBuf,
    /// Search engine template for the dashboard search bar; `{}` is replaced
    /// by the url-encoded query. None hides the search bar.
    pub search_url: Option<String>,
    pub monitor: MonitorConfig,
    pub archive: ArchiveConfig,
    /// Scheduled database backups (`VACUUM INTO` snapshots). Off unless
    /// `enabled = true`.
    pub backup: BackupConfig,
    /// Services shown (and polled) on the dashboard.
    pub services: Vec<ServiceDef>,
    /// Static bookmark groups shown on the dashboard.
    pub bookmarks: Vec<BookmarkGroup>,
    /// Dashboard layout: columns of widgets. When empty, a default single
    /// column (search + services + bookmarks) is derived from the fields
    /// above — see `widgets::resolve_layout`.
    pub columns: Vec<ColumnConfig>,
    /// Home Assistant integration (Home tab: temperature history + light
    /// control). Feature is off when `base_url` is `None`.
    pub home_assistant: HomeAssistantConfig,
    /// Append `Secure` to the session cookie. Turn on when the server is
    /// reached over HTTPS (reverse proxy with TLS); off by default because
    /// plain-http LAN setups would otherwise lose their session cookie.
    pub secure_cookies: bool,
    /// Push notifications via ntfy (service alerts + calendar reminders).
    /// Feature is off when `ntfy_url` is `None`.
    pub notifications: NotificationsConfig,
    /// Trust an authenticating reverse proxy (authentik via traefik). Feature
    /// is off unless `secret` is set.
    pub forward_auth: ForwardAuthConfig,
}

/// Trust an authenticating reverse proxy that forwards the user's identity in
/// headers. The whole feature is OFF when `secret` is `None` (the default):
/// no request header is ever trusted, so a direct/tailnet client cannot forge
/// an identity. When enabled, chaos trusts `username_header`/`name_header`
/// only on requests that also carry `secret_header` matching `secret`.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct ForwardAuthConfig {
    /// Shared secret the reverse proxy sends in `secret_header`. When `None`,
    /// forward-auth is DISABLED and no request header is ever trusted.
    pub secret: Option<String>,
    /// Header carrying the authenticated username (identity key).
    pub username_header: String,
    /// Header carrying the display name (used for auto-provisioned users).
    pub name_header: String,
    /// Header carrying the shared secret.
    pub secret_header: String,
}

impl Default for ForwardAuthConfig {
    fn default() -> Self {
        Self {
            secret: None,
            username_header: "x-authentik-username".into(),
            name_header: "x-authentik-name".into(),
            secret_header: "x-chaos-proxy-secret".into(),
        }
    }
}

impl ForwardAuthConfig {
    /// Whether forward-auth is enabled (a shared secret is configured).
    // Consumed by callers (extractor) and tests; keep as public API surface.
    #[allow(dead_code)]
    pub fn enabled(&self) -> bool {
        self.secret.is_some()
    }
}

/// Push notifications via ntfy. The whole feature is off when `ntfy_url`
/// is `None` (the default): no HTTP client, no background task, nothing.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct NotificationsConfig {
    /// ntfy server base URL, e.g. `https://ntfy.sh` or a self-hosted
    /// instance. `None` disables notifications entirely.
    pub ntfy_url: Option<url::Url>,
    /// Topic notifications are published to (`{ntfy_url}/{topic}`).
    pub topic: String,
    /// Bearer token for protected topics (ntfy access tokens).
    pub token: Option<String>,
    /// Notify on service Down/Degraded ↔ Up transitions.
    pub service_alerts: bool,
    /// Remind about calendar events shortly before they start.
    pub calendar_reminders: bool,
    /// How long before an event starts the reminder fires.
    pub reminder_lead_minutes: u64,
}

impl Default for NotificationsConfig {
    fn default() -> Self {
        Self {
            ntfy_url: None,
            topic: String::new(),
            token: None,
            service_alerts: true,
            calendar_reminders: true,
            reminder_lead_minutes: 15,
        }
    }
}

#[derive(Debug, Clone, Default, Serialize, Deserialize)]
#[serde(default)]
pub struct HomeAssistantConfig {
    /// Home Assistant base URL, e.g. `http://zeus:8093` (reverse-proxied to
    /// the instance). `None` disables the whole Home tab.
    pub base_url: Option<url::Url>,
    /// File holding a Home Assistant long-lived access token (an agenix
    /// secret path on NixOS). Read once at startup.
    pub token_file: Option<PathBuf>,
    /// Temperature sensors shown on the Home tab.
    pub sensors: Vec<HomeEntityDef>,
    /// Lights controllable from the Home tab.
    pub lights: Vec<HomeEntityDef>,
}

/// One Home Assistant entity exposed on the Home tab. The `entity_id` is
/// server-side only — clients only ever see `id`/`label`.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct HomeEntityDef {
    pub id: String,
    /// Display name. When omitted the server asks Home Assistant for one:
    /// the entity's area (room) first, then its friendly name.
    #[serde(default)]
    pub label: Option<String>,
    pub entity_id: String,
    /// Battery entity for this sensor. When omitted it is derived from
    /// `entity_id` by suffix swap (`..._temperature` → `..._battery`,
    /// `..._temperature_2` → `..._battery_2`); set it explicitly when the
    /// names don't follow that pattern.
    #[serde(default)]
    pub battery_entity_id: Option<String>,
}

/// One dashboard column as written in configuration. Widget instance ids are
/// assigned by the server, so the config only lists widget definitions.
#[derive(Debug, Clone, Default, Serialize, Deserialize)]
#[serde(default)]
pub struct ColumnConfig {
    pub size: ColumnSize,
    pub widgets: Vec<Widget>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct ArchiveConfig {
    /// Master switch for the archiver worker.
    pub enabled: bool,
    /// Archive new links automatically on save.
    pub auto: bool,
    /// Directory where snapshots are stored (one <link-id>.html per link).
    pub dir: PathBuf,
    /// monolith executable; on NixOS provided via the service PATH.
    pub monolith_bin: String,
    /// Per-page snapshot timeout.
    pub timeout_secs: u64,
}

impl Default for ArchiveConfig {
    fn default() -> Self {
        Self {
            enabled: true,
            auto: true,
            dir: PathBuf::from("archives"),
            monolith_bin: "monolith".into(),
            timeout_secs: 120,
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct BackupConfig {
    /// Master switch for the scheduled backup task.
    pub enabled: bool,
    /// Directory where snapshots land (`chaos-<timestamp>.db`). Relative
    /// paths resolve against the working directory (`/var/lib/chaos`
    /// under the NixOS module), like `db_path` and `archive.dir`.
    pub dir: PathBuf,
    /// Hours between two snapshots (clamped to at least 1).
    pub interval_hours: u64,
    /// How many snapshots to keep; older ones are pruned after each run.
    pub keep: usize,
}

impl Default for BackupConfig {
    fn default() -> Self {
        Self {
            enabled: false,
            dir: PathBuf::from("backups"),
            interval_hours: 24,
            keep: 14,
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct MonitorConfig {
    /// Seconds between two polling sweeps.
    pub interval_secs: u64,
    /// Per-request timeout in milliseconds.
    pub timeout_ms: u64,
}

impl Default for Config {
    fn default() -> Self {
        Self {
            listen: "0.0.0.0:4600".parse().expect("valid default listen addr"),
            static_dir: None,
            db_path: PathBuf::from("chaos.db"),
            icon_cache_dir: PathBuf::from("icons"),
            search_url: None,
            monitor: MonitorConfig::default(),
            archive: ArchiveConfig::default(),
            backup: BackupConfig::default(),
            services: Vec::new(),
            bookmarks: Vec::new(),
            columns: Vec::new(),
            home_assistant: HomeAssistantConfig::default(),
            secure_cookies: false,
            notifications: NotificationsConfig::default(),
            forward_auth: ForwardAuthConfig::default(),
        }
    }
}

impl Default for MonitorConfig {
    fn default() -> Self {
        Self {
            interval_secs: 60,
            timeout_ms: 5_000,
        }
    }
}

pub fn load() -> anyhow::Result<Config> {
    let config_path = std::env::var("CHAOS_CONFIG").unwrap_or_else(|_| "chaos.toml".into());

    let config = Figment::from(Serialized::defaults(Config::default()))
        .merge(Toml::file(&config_path))
        .merge(Env::prefixed("CHAOS_").split("__"))
        .extract::<Config>()?;
    Ok(config)
}

#[cfg(test)]
mod tests {
    use figment::providers::Format;

    #[test]
    fn legacy_apps_section_is_ignored_and_bookmark_android_package_parses() {
        let toml = r#"
            [[apps]]
            id = "yomu"
            title = "Yomu"
            url = "http://zeus:4700"

            [[bookmarks]]
            title = "Main"
            [[bookmarks.links]]
            title = "Yomu"
            url = "http://zeus:4700"
            android_package = "xyz.tdbm.yomu"
        "#;
        let config: super::Config = figment::Figment::from(
            figment::providers::Serialized::defaults(super::Config::default()),
        )
        .merge(figment::providers::Toml::string(toml))
        .extract()
        .expect("legacy apps key must not break config parsing");
        assert_eq!(
            config.bookmarks[0].links[0].android_package.as_deref(),
            Some("xyz.tdbm.yomu")
        );
    }

    #[test]
    fn secure_cookies_defaults_off_and_parses() {
        let config = super::Config::default();
        assert!(!config.secure_cookies);

        let config: super::Config = figment::Figment::from(
            figment::providers::Serialized::defaults(super::Config::default()),
        )
        .merge(figment::providers::Toml::string("secure_cookies = true"))
        .extract()
        .expect("secure_cookies must parse");
        assert!(config.secure_cookies);
    }

    #[test]
    fn notifications_section_parses_and_defaults_off() {
        let toml = r#"
            [notifications]
            ntfy_url = "https://ntfy.example.com"
            topic = "chaos"
            token = "tk_secret"
            reminder_lead_minutes = 30
        "#;
        let config: super::Config = figment::Figment::from(
            figment::providers::Serialized::defaults(super::Config::default()),
        )
        .merge(figment::providers::Toml::string(toml))
        .extract()
        .expect("notifications section must parse");
        let n = &config.notifications;
        assert_eq!(
            n.ntfy_url.as_ref().map(url::Url::as_str),
            Some("https://ntfy.example.com/")
        );
        assert_eq!(n.topic, "chaos");
        assert_eq!(n.token.as_deref(), Some("tk_secret"));
        assert!(n.service_alerts, "service_alerts defaults to true");
        assert!(n.calendar_reminders, "calendar_reminders defaults to true");
        assert_eq!(n.reminder_lead_minutes, 30);

        // No section at all → feature off (no url), defaults intact.
        let default = super::Config::default();
        assert!(default.notifications.ntfy_url.is_none());
        assert_eq!(default.notifications.reminder_lead_minutes, 15);
    }

    #[test]
    fn forward_auth_defaults_off_with_authentik_headers() {
        let c = super::ForwardAuthConfig::default();
        assert!(c.secret.is_none());
        assert!(!c.enabled());
        assert_eq!(c.username_header, "x-authentik-username");
        assert_eq!(c.name_header, "x-authentik-name");
        assert_eq!(c.secret_header, "x-chaos-proxy-secret");

        // Setting a secret via TOML enables the feature.
        let config: super::Config = figment::Figment::from(
            figment::providers::Serialized::defaults(super::Config::default()),
        )
        .merge(figment::providers::Toml::string(
            "[forward_auth]\nsecret = \"s3cret\"",
        ))
        .extract()
        .expect("forward_auth section must parse");
        assert!(config.forward_auth.enabled());
        assert_eq!(config.forward_auth.secret.as_deref(), Some("s3cret"));
        // Untouched fields keep their defaults.
        assert_eq!(config.forward_auth.username_header, "x-authentik-username");
    }

    #[test]
    fn backup_section_parses_and_defaults_are_sane() {
        let toml = r#"
            [backup]
            enabled = true
        "#;
        let config: super::Config = figment::Figment::from(
            figment::providers::Serialized::defaults(super::Config::default()),
        )
        .merge(figment::providers::Toml::string(toml))
        .extract()
        .expect("backup section must parse");
        assert!(config.backup.enabled);
        assert_eq!(config.backup.dir, std::path::PathBuf::from("backups"));
        assert_eq!(config.backup.interval_hours, 24);
        assert_eq!(config.backup.keep, 14);
        assert!(
            !super::Config::default().backup.enabled,
            "backups are opt-in"
        );
    }
}
